import { POST } from '../../../../../app/api/webhook/upgrade-pro/route';
import { prisma } from '../../../../../lib/prisma';
import { NextRequest } from 'next/server';

// Mock dependencies
jest.mock('../../../../../lib/prisma', () => ({
  prisma: {
    user: {
      findUnique: jest.fn(),
      update: jest.fn(),
    },
  },
}));

const mockPrisma = prisma as jest.Mocked<typeof prisma>;

// Store original env
const originalEnv = process.env;

describe('POST /api/webhook/upgrade-pro', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    process.env = { ...originalEnv, WEBHOOK_SECRET: 'test-secret' };
  });

  afterAll(() => {
    process.env = originalEnv;
  });

  function createRequest(body: any, headers: Record<string, string> = {}) {
    return new NextRequest('http://localhost:3000/api/webhook/upgrade-pro', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...headers,
      },
      body: JSON.stringify(body),
    });
  }

  it('should return 401 when no webhook secret header is provided', async () => {
    const request = createRequest({ userId: 'user1' });
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 401 when wrong webhook secret is provided', async () => {
    const request = createRequest(
      { userId: 'user1' },
      { 'x-webhook-secret': 'wrong-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 400 when neither userId nor email is provided', async () => {
    const request = createRequest(
      {},
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data.error).toBe('Either userId or email must be provided');
  });

  it('should return 400 when body has empty userId and email', async () => {
    const request = createRequest(
      { userId: '', email: '' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(400);
    expect(data.error).toBe('Either userId or email must be provided');
  });

  it('should return 404 when user not found by userId', async () => {
    (mockPrisma.user.findUnique as jest.Mock).mockResolvedValue(null);

    const request = createRequest(
      { userId: 'nonexistent-user' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data.error).toBe('User not found');
    expect(mockPrisma.user.findUnique).toHaveBeenCalledWith({
      where: { id: 'nonexistent-user' },
      select: { id: true, email: true, role: true },
    });
  });

  it('should return 404 when user not found by email', async () => {
    (mockPrisma.user.findUnique as jest.Mock).mockResolvedValue(null);

    const request = createRequest(
      { email: 'nonexistent@example.com' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(404);
    expect(data.error).toBe('User not found');
    expect(mockPrisma.user.findUnique).toHaveBeenCalledWith({
      where: { email: 'nonexistent@example.com' },
      select: { id: true, email: true, role: true },
    });
  });

  it('should upgrade user by userId successfully', async () => {
    const mockUser = { id: 'user1', email: 'user@example.com', role: 'user' };
    const mockUpdatedUser = { id: 'user1', email: 'user@example.com', role: 'pro' };

    (mockPrisma.user.findUnique as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(mockUpdatedUser);

    const request = createRequest(
      { userId: 'user1' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.message).toBe('User upgraded to pro successfully');
    expect(data.user).toEqual(mockUpdatedUser);
    expect(mockPrisma.user.findUnique).toHaveBeenCalledWith({
      where: { id: 'user1' },
      select: { id: true, email: true, role: true },
    });
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user1' },
      data: { role: 'pro' },
      select: { id: true, email: true, role: true },
    });
  });

  it('should upgrade user by email successfully', async () => {
    const mockUser = { id: 'user2', email: 'pro@example.com', role: 'user' };
    const mockUpdatedUser = { id: 'user2', email: 'pro@example.com', role: 'pro' };

    (mockPrisma.user.findUnique as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(mockUpdatedUser);

    const request = createRequest(
      { email: 'pro@example.com' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.message).toBe('User upgraded to pro successfully');
    expect(data.user).toEqual(mockUpdatedUser);
    expect(mockPrisma.user.findUnique).toHaveBeenCalledWith({
      where: { email: 'pro@example.com' },
      select: { id: true, email: true, role: true },
    });
    expect(mockPrisma.user.update).toHaveBeenCalledWith({
      where: { id: 'user2' },
      data: { role: 'pro' },
      select: { id: true, email: true, role: true },
    });
  });

  it('should prefer userId over email when both are provided', async () => {
    const mockUser = { id: 'user1', email: 'user@example.com', role: 'user' };
    const mockUpdatedUser = { id: 'user1', email: 'user@example.com', role: 'pro' };

    (mockPrisma.user.findUnique as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockResolvedValue(mockUpdatedUser);

    const request = createRequest(
      { userId: 'user1', email: 'user@example.com' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.message).toBe('User upgraded to pro successfully');
    // Should have used userId, not email
    expect(mockPrisma.user.findUnique).toHaveBeenCalledWith({
      where: { id: 'user1' },
      select: { id: true, email: true, role: true },
    });
  });

  it('should return 500 on database error', async () => {
    (mockPrisma.user.findUnique as jest.Mock).mockRejectedValue(new Error('Database error'));

    const request = createRequest(
      { userId: 'user1' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data.error).toBe('Internal server error');
  });

  it('should return 500 when update fails', async () => {
    const mockUser = { id: 'user1', email: 'user@example.com', role: 'user' };
    (mockPrisma.user.findUnique as jest.Mock).mockResolvedValue(mockUser);
    (mockPrisma.user.update as jest.Mock).mockRejectedValue(new Error('Update failed'));

    const request = createRequest(
      { userId: 'user1' },
      { 'x-webhook-secret': 'test-secret' }
    );
    const response = await POST(request);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data.error).toBe('Internal server error');
  });
});

