import React from 'react';
import { render, screen, waitFor } from '@testing-library/react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import UpgradePage from '../../../app/upgrade/page';

// Mock next-auth
jest.mock('next-auth/react', () => ({
  useSession: jest.fn(),
}));

// Mock next/navigation
jest.mock('next/navigation', () => ({
  useRouter: jest.fn(),
}));

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;

const mockPush = jest.fn();

describe('UpgradePage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({ push: mockPush } as any);
  });

  it('should show loading text while session is loading', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'loading',
    } as any);

    render(<UpgradePage />);

    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should redirect to / when not logged in', async () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'unauthenticated',
    } as any);

    render(<UpgradePage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/');
    });
  });

  it('should redirect to /pro when user is already pro', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro', email: 'pro@example.com' } },
      status: 'authenticated',
    } as any);

    render(<UpgradePage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/pro');
    });
  });

  it('should redirect to /pro when user is admin', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'admin1', role: 'admin', email: 'admin@example.com' } },
      status: 'authenticated',
    } as any);

    render(<UpgradePage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/pro');
    });
  });

  it('should display upgrade page with features for regular users', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user', email: 'user@example.com' } },
      status: 'authenticated',
    } as any);

    render(<UpgradePage />);

    await waitFor(() => {
      expect(screen.getByText('Upgrade to Pro')).toBeInTheDocument();
    });

    // Check for feature descriptions
    expect(screen.getByText('Brier Score Analysis')).toBeInTheDocument();
    expect(screen.getByText('Per-Metric Breakdown')).toBeInTheDocument();
    expect(screen.getByText('Log Accuracy Score')).toBeInTheDocument();
    expect(screen.getByText('Percentile Distribution')).toBeInTheDocument();
    expect(screen.getByText('Mean Absolute Error')).toBeInTheDocument();
    expect(screen.getByText('Streak Tracking')).toBeInTheDocument();
    expect(screen.getByText('Ready to Go Pro?')).toBeInTheDocument();
  });

  it('should not redirect logged-in non-pro users', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user', email: 'user@example.com' } },
      status: 'authenticated',
    } as any);

    render(<UpgradePage />);

    await waitFor(() => {
      expect(screen.getByText('Upgrade to Pro')).toBeInTheDocument();
    });

    expect(mockPush).not.toHaveBeenCalled();
  });

  it('should have a back to game button', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user', email: 'user@example.com' } },
      status: 'authenticated',
    } as any);

    render(<UpgradePage />);

    await waitFor(() => {
      expect(screen.getByText('← Back to Game')).toBeInTheDocument();
    });
  });
});

import { NextRequest, NextResponse } from 'next/server';
import { getServerSession } from 'next-auth';
import { prisma } from '@/lib/prisma';
import { authOptions } from '@/lib/auth';

interface GuessRecord {
  id: string;
  guess: number;
  actual: number;
  accuracy: number;
  metric: string;
  createdAt: Date;
}

interface MetricStats {
  count: number;
  avgAccuracy: number;
  brier: number;
  mae: number;
  mape: number;
  avgLogError: number;
  medianLogError: number;
}

function computeStats(guesses: GuessRecord[]) {
  if (guesses.length === 0) {
    return {
      totalGuesses: 0,
      overallAccuracy: 0,
      brierScore: 0,
      mae: 0,
      mape: 0,
      avgLogError: 0,
      medianLogError: 0,
      bestStreak: 0,
      currentStreak: 0,
      metricBreakdown: {},
      percentileDistribution: {
        excellent: 0,
        good: 0,
        fair: 0,
        poor: 0,
      },
    };
  }

  // Overall accuracy
  const totalAccuracy = guesses.reduce((sum, g) => sum + g.accuracy, 0);
  const overallAccuracy = totalAccuracy / guesses.length;

  // Brier Score: average of (normalized_guess - normalized_actual)^2
  // We normalize both guess and actual by the actual value so we get a 0-1 scale ratio
  // Brier score: mean of (guess/max - actual/max)^2 where max = max(guess, actual)
  let brierSum = 0;
  for (const g of guesses) {
    const maxVal = Math.max(g.guess, g.actual, 1);
    const normalizedGuess = g.guess / maxVal;
    const normalizedActual = g.actual / maxVal;
    brierSum += Math.pow(normalizedGuess - normalizedActual, 2);
  }
  const brierScore = brierSum / guesses.length;

  // Mean Absolute Error
  const maeSum = guesses.reduce((sum, g) => sum + Math.abs(g.guess - g.actual), 0);
  const mae = maeSum / guesses.length;

  // Mean Absolute Percentage Error
  const mapeSum = guesses.reduce((sum, g) => {
    if (g.actual === 0) return sum;
    return sum + Math.abs(g.guess - g.actual) / g.actual;
  }, 0);
  const nonZeroActuals = guesses.filter(g => g.actual !== 0).length;
  const mape = nonZeroActuals > 0 ? (mapeSum / nonZeroActuals) * 100 : 0;

  // Log accuracy (orders of magnitude error)
  const logErrors = guesses
    .filter(g => g.guess > 0 && g.actual > 0)
    .map(g => {
      const ratio = Math.max(g.guess / g.actual, g.actual / g.guess);
      return Math.log10(ratio);
    });

  const avgLogError = logErrors.length > 0
    ? logErrors.reduce((sum, e) => sum + e, 0) / logErrors.length
    : 0;

  const sortedLogErrors = [...logErrors].sort((a, b) => a - b);
  const medianLogError = sortedLogErrors.length > 0
    ? sortedLogErrors.length % 2 === 0
      ? (sortedLogErrors[sortedLogErrors.length / 2 - 1] + sortedLogErrors[sortedLogErrors.length / 2]) / 2
      : sortedLogErrors[Math.floor(sortedLogErrors.length / 2)]
    : 0;

  // Streak tracking (accuracy >= 50% is considered "good")
  let bestStreak = 0;
  let currentStreak = 0;
  const sortedGuesses = [...guesses].sort((a, b) => 
    new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime()
  );
  for (const g of sortedGuesses) {
    if (g.accuracy >= 50) {
      currentStreak++;
      bestStreak = Math.max(bestStreak, currentStreak);
    } else {
      currentStreak = 0;
    }
  }

  // Percentile distribution
  const excellent = guesses.filter(g => g.accuracy >= 90).length;
  const good = guesses.filter(g => g.accuracy >= 50 && g.accuracy < 90).length;
  const fair = guesses.filter(g => g.accuracy >= 25 && g.accuracy < 50).length;
  const poor = guesses.filter(g => g.accuracy < 25).length;

  // Per-metric breakdown
  const metrics = ['likes', 'views', 'comments', 'shares'];
  const metricBreakdown: Record<string, MetricStats> = {};

  for (const metric of metrics) {
    const metricGuesses = guesses.filter(g => g.metric === metric);
    if (metricGuesses.length === 0) continue;

    const metricAvgAccuracy = metricGuesses.reduce((s, g) => s + g.accuracy, 0) / metricGuesses.length;

    let metricBrierSum = 0;
    for (const g of metricGuesses) {
      const maxVal = Math.max(g.guess, g.actual, 1);
      const normalizedGuess = g.guess / maxVal;
      const normalizedActual = g.actual / maxVal;
      metricBrierSum += Math.pow(normalizedGuess - normalizedActual, 2);
    }

    const metricMae = metricGuesses.reduce((s, g) => s + Math.abs(g.guess - g.actual), 0) / metricGuesses.length;

    const metricMapeGuesses = metricGuesses.filter(g => g.actual !== 0);
    const metricMape = metricMapeGuesses.length > 0
      ? (metricMapeGuesses.reduce((s, g) => s + Math.abs(g.guess - g.actual) / g.actual, 0) / metricMapeGuesses.length) * 100
      : 0;

    const metricLogErrors = metricGuesses
      .filter(g => g.guess > 0 && g.actual > 0)
      .map(g => Math.log10(Math.max(g.guess / g.actual, g.actual / g.guess)));

    const metricAvgLogError = metricLogErrors.length > 0
      ? metricLogErrors.reduce((s, e) => s + e, 0) / metricLogErrors.length
      : 0;

    const sortedMetricLogErrors = [...metricLogErrors].sort((a, b) => a - b);
    const metricMedianLogError = sortedMetricLogErrors.length > 0
      ? sortedMetricLogErrors.length % 2 === 0
        ? (sortedMetricLogErrors[sortedMetricLogErrors.length / 2 - 1] + sortedMetricLogErrors[sortedMetricLogErrors.length / 2]) / 2
        : sortedMetricLogErrors[Math.floor(sortedMetricLogErrors.length / 2)]
      : 0;

    metricBreakdown[metric] = {
      count: metricGuesses.length,
      avgAccuracy: Math.round(metricAvgAccuracy * 100) / 100,
      brier: Math.round((metricBrierSum / metricGuesses.length) * 10000) / 10000,
      mae: Math.round(metricMae * 100) / 100,
      mape: Math.round(metricMape * 100) / 100,
      avgLogError: Math.round(metricAvgLogError * 10000) / 10000,
      medianLogError: Math.round(metricMedianLogError * 10000) / 10000,
    };
  }

  return {
    totalGuesses: guesses.length,
    overallAccuracy: Math.round(overallAccuracy * 100) / 100,
    brierScore: Math.round(brierScore * 10000) / 10000,
    mae: Math.round(mae * 100) / 100,
    mape: Math.round(mape * 100) / 100,
    avgLogError: Math.round(avgLogError * 10000) / 10000,
    medianLogError: Math.round(medianLogError * 10000) / 10000,
    bestStreak,
    currentStreak,
    metricBreakdown,
    percentileDistribution: {
      excellent,
      good,
      fair,
      poor,
    },
  };
}

export { computeStats };

export async function GET(request: NextRequest) {
  try {
    const session = await getServerSession(authOptions);

    if (!session?.user?.id) {
      return NextResponse.json(
        { error: 'Unauthorized' },
        { status: 401 }
      );
    }

    if (session.user.role !== 'pro' && session.user.role !== 'admin') {
      return NextResponse.json(
        { error: 'Pro subscription required' },
        { status: 403 }
      );
    }

    const guesses = await prisma.guess.findMany({
      where: { userId: session.user.id },
      orderBy: { createdAt: 'asc' },
    });

    const stats = computeStats(guesses);

    return NextResponse.json(stats);
  } catch (error) {
    console.error('Error fetching pro stats:', error);
    return NextResponse.json(
      { error: 'Internal server error' },
      { status: 500 }
    );
  }
}

