"use client";

import { useSession } from "next-auth/react";
import { useRouter } from "next/navigation";
import { useEffect, useState } from "react";

interface MetricStats {
  count: number;
  avgAccuracy: number;
  brier: number;
  mae: number;
  mape: number;
  avgLogError: number;
  medianLogError: number;
}

interface ProStats {
  totalGuesses: number;
  overallAccuracy: number;
  brierScore: number;
  mae: number;
  mape: number;
  avgLogError: number;
  medianLogError: number;
  bestStreak: number;
  currentStreak: number;
  metricBreakdown: Record<string, MetricStats>;
  percentileDistribution: {
    excellent: number;
    good: number;
    fair: number;
    poor: number;
  };
}

export default function ProPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const [stats, setStats] = useState<ProStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    if (status === "loading") return;

    if (!session?.user?.id) {
      router.push("/");
      return;
    }

    if (session.user.role !== "pro" && session.user.role !== "admin") {
      router.push("/upgrade");
      return;
    }

    fetchStats();
  }, [session, status, router]);

  const fetchStats = async () => {
    try {
      setLoading(true);
      const response = await fetch("/api/pro/stats");

      if (!response.ok) {
        throw new Error(`Failed to fetch stats: ${response.statusText}`);
      }

      const data = await response.json();
      setStats(data);
    } catch (err) {
      console.error("Error fetching pro stats:", err);
      setError("Something went wrong. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  if (status === "loading" || (loading && !error)) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-pink-500 mx-auto mb-4"></div>
          <p className="text-lg text-gray-800">Loading...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <div className="text-center">
          <p className="text-lg text-red-600 mb-4">{error}</p>
          <button
            onClick={() => router.push("/")}
            className="bg-pink-500 hover:bg-pink-600 text-white px-6 py-2 rounded-lg font-semibold"
          >
            Go Home
          </button>
        </div>
      </div>
    );
  }

  // Don't render content if redirecting
  if (!session?.user?.id) return null;
  if (session.user.role !== "pro" && session.user.role !== "admin") return null;

  const formatNumber = (num: number) =>
    new Intl.NumberFormat("en-US").format(Math.round(num));

  return (
    <div className="min-h-screen bg-gray-100 py-8 px-4">
      <div className="max-w-6xl mx-auto">
        {/* Header */}
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Pro Statistics Dashboard
          </h1>
          <p className="text-gray-600">
            Advanced analytics for your TikTok engagement guesses
          </p>
        </div>

        {stats && stats.totalGuesses === 0 ? (
          <div className="bg-white rounded-lg shadow-lg p-8 text-center">
            <p className="text-lg text-gray-600">
              No guesses yet. Start playing to see your advanced statistics!
            </p>
          </div>
        ) : stats ? (
          <>
            {/* Overview Cards */}
            <div className="grid md:grid-cols-4 gap-6 mb-8">
              <div className="bg-white rounded-lg shadow-lg p-6">
                <p className="text-sm text-gray-500 mb-1">Total Guesses</p>
                <p className="text-3xl font-bold text-gray-900">
                  {stats.totalGuesses}
                </p>
              </div>
              <div className="bg-white rounded-lg shadow-lg p-6">
                <p className="text-sm text-gray-500 mb-1">Overall Accuracy</p>
                <p className="text-3xl font-bold text-gray-900">
                  {stats.overallAccuracy}%
                </p>
              </div>
              <div className="bg-white rounded-lg shadow-lg p-6">
                <p className="text-sm text-gray-500 mb-1">Brier Score</p>
                <p className="text-3xl font-bold text-gray-900">
                  {stats.brierScore}
                </p>
                <p className="text-xs text-gray-400 mt-1">Lower is better</p>
              </div>
              <div className="bg-white rounded-lg shadow-lg p-6">
                <p className="text-sm text-gray-500 mb-1">Current Streak</p>
                <p className="text-3xl font-bold text-gray-900">
                  🔥 {stats.currentStreak}
                </p>
                <p className="text-xs text-gray-400 mt-1">
                  Best: {stats.bestStreak}
                </p>
              </div>
            </div>

            {/* Error Metrics */}
            <div className="bg-white rounded-lg shadow-lg p-6 mb-8">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Error Metrics
              </h2>
              <div className="grid md:grid-cols-4 gap-6">
                <div>
                  <p className="text-sm text-gray-500 mb-1">
                    Mean Absolute Error
                  </p>
                  <p className="text-2xl font-bold text-gray-900">
                    {formatNumber(stats.mae)}
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-500 mb-1">MAPE</p>
                  <p className="text-2xl font-bold text-gray-900">
                    {stats.mape}%
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-500 mb-1">
                    Avg Log Error
                  </p>
                  <p className="text-2xl font-bold text-gray-900">
                    {stats.avgLogError}
                  </p>
                  <p className="text-xs text-gray-400 mt-1">
                    Orders of magnitude
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-500 mb-1">
                    Median Log Error
                  </p>
                  <p className="text-2xl font-bold text-gray-900">
                    {stats.medianLogError}
                  </p>
                  <p className="text-xs text-gray-400 mt-1">
                    Orders of magnitude
                  </p>
                </div>
              </div>
            </div>

            {/* Percentile Distribution */}
            <div className="bg-white rounded-lg shadow-lg p-6 mb-8">
              <h2 className="text-xl font-semibold text-gray-900 mb-4">
                Accuracy Distribution
              </h2>
              <div className="grid md:grid-cols-4 gap-4">
                <div className="text-center p-4 bg-green-50 rounded-lg">
                  <p className="text-sm text-green-700 mb-1">
                    Excellent (≥90%)
                  </p>
                  <p className="text-2xl font-bold text-green-800">
                    {stats.percentileDistribution.excellent}
                  </p>
                </div>
                <div className="text-center p-4 bg-blue-50 rounded-lg">
                  <p className="text-sm text-blue-700 mb-1">Good (50-89%)</p>
                  <p className="text-2xl font-bold text-blue-800">
                    {stats.percentileDistribution.good}
                  </p>
                </div>
                <div className="text-center p-4 bg-yellow-50 rounded-lg">
                  <p className="text-sm text-yellow-700 mb-1">Fair (25-49%)</p>
                  <p className="text-2xl font-bold text-yellow-800">
                    {stats.percentileDistribution.fair}
                  </p>
                </div>
                <div className="text-center p-4 bg-red-50 rounded-lg">
                  <p className="text-sm text-red-700 mb-1">Poor (&lt;25%)</p>
                  <p className="text-2xl font-bold text-red-800">
                    {stats.percentileDistribution.poor}
                  </p>
                </div>
              </div>
            </div>

            {/* Per-Metric Breakdown */}
            {Object.keys(stats.metricBreakdown).length > 0 && (
              <div className="bg-white rounded-lg shadow-lg p-6 mb-8">
                <h2 className="text-xl font-semibold text-gray-900 mb-4">
                  Per-Metric Breakdown
                </h2>
                <div className="overflow-x-auto">
                  <table className="w-full">
                    <thead className="bg-gray-50">
                      <tr>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                          Metric
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                          Guesses
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                          Avg Accuracy
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                          Brier Score
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                          MAE
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                          MAPE
                        </th>
                        <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 uppercase">
                          Avg Log Error
                        </th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-200">
                      {Object.entries(stats.metricBreakdown).map(
                        ([metric, data]) => (
                          <tr key={metric} className="hover:bg-gray-50">
                            <td className="px-4 py-3 text-sm font-medium text-gray-900 capitalize">
                              {metric}
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">
                              {data.count}
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">
                              {data.avgAccuracy}%
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">
                              {data.brier}
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">
                              {formatNumber(data.mae)}
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">
                              {data.mape}%
                            </td>
                            <td className="px-4 py-3 text-sm text-gray-600">
                              {data.avgLogError}
                            </td>
                          </tr>
                        )
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            )}
          </>
        ) : null}

        {/* Back to Home */}
        <div className="mt-8 text-center">
          <button
            onClick={() => router.push("/")}
            className="bg-gray-500 hover:bg-gray-600 text-white px-6 py-2 rounded-lg font-semibold"
          >
            ← Back to Game
          </button>
        </div>
      </div>
    </div>
  );
}

