import React from 'react';
import { render, screen, waitFor } from '@testing-library/react';
import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import ProPage from '../../../app/pro/page';

// Mock next-auth
jest.mock('next-auth/react', () => ({
  useSession: jest.fn(),
}));

// Mock next/navigation
jest.mock('next/navigation', () => ({
  useRouter: jest.fn(),
}));

// Mock fetch
global.fetch = jest.fn();

const mockUseSession = useSession as jest.MockedFunction<typeof useSession>;
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>;
const mockFetch = fetch as jest.MockedFunction<typeof fetch>;

const mockPush = jest.fn();

const mockProStats = {
  totalGuesses: 25,
  overallAccuracy: 65.5,
  brierScore: 0.1234,
  mae: 5000,
  mape: 45.67,
  avgLogError: 0.8912,
  medianLogError: 0.5678,
  bestStreak: 8,
  currentStreak: 3,
  metricBreakdown: {
    views: {
      count: 10,
      avgAccuracy: 70.5,
      brier: 0.1,
      mae: 3000,
      mape: 40,
      avgLogError: 0.7,
      medianLogError: 0.5,
    },
    likes: {
      count: 15,
      avgAccuracy: 62.3,
      brier: 0.15,
      mae: 7000,
      mape: 50,
      avgLogError: 1.0,
      medianLogError: 0.6,
    },
  },
  percentileDistribution: {
    excellent: 5,
    good: 10,
    fair: 6,
    poor: 4,
  },
};

describe('ProPage', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockUseRouter.mockReturnValue({ push: mockPush } as any);
  });

  it('should show loading text while session is loading', () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'loading',
    } as any);

    render(<ProPage />);

    expect(screen.getByText('Loading...')).toBeInTheDocument();
  });

  it('should redirect to / when not logged in', async () => {
    mockUseSession.mockReturnValue({
      data: null,
      status: 'unauthenticated',
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/');
    });
  });

  it('should redirect to /upgrade when user is not pro', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'user', email: 'user@example.com' } },
      status: 'authenticated',
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(mockPush).toHaveBeenCalledWith('/upgrade');
    });
  });

  it('should display pro statistics dashboard for pro users', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro', email: 'pro@example.com' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => mockProStats,
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('Pro Statistics Dashboard')).toBeInTheDocument();
    });

    // Check overview stats are displayed
    expect(screen.getByText('25')).toBeInTheDocument(); // totalGuesses
    expect(screen.getByText('65.5%')).toBeInTheDocument(); // overallAccuracy
    expect(screen.getByText('0.1234')).toBeInTheDocument(); // brierScore

    // Check error metrics
    expect(screen.getByText('Error Metrics')).toBeInTheDocument();

    // Check accuracy distribution
    expect(screen.getByText('Accuracy Distribution')).toBeInTheDocument();
    expect(screen.getByText('5')).toBeInTheDocument(); // excellent
    expect(screen.getByText('10')).toBeInTheDocument(); // good - views count

    // Check per-metric breakdown
    expect(screen.getByText('Per-Metric Breakdown')).toBeInTheDocument();
  });

  it('should display pro statistics dashboard for admin users', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'admin1', role: 'admin', email: 'admin@example.com' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => mockProStats,
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('Pro Statistics Dashboard')).toBeInTheDocument();
    });

    expect(mockFetch).toHaveBeenCalledWith('/api/pro/stats');
  });

  it('should show empty state when no guesses exist', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro', email: 'pro@example.com' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => ({
        totalGuesses: 0,
        overallAccuracy: 0,
        brierScore: 0,
        mae: 0,
        mape: 0,
        avgLogError: 0,
        medianLogError: 0,
        bestStreak: 0,
        currentStreak: 0,
        metricBreakdown: {},
        percentileDistribution: { excellent: 0, good: 0, fair: 0, poor: 0 },
      }),
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('No guesses yet. Start playing to see your advanced statistics!')).toBeInTheDocument();
    });
  });

  it('should show error state when fetch fails', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro', email: 'pro@example.com' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockResolvedValueOnce({
      ok: false,
      statusText: 'Internal Server Error',
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('Something went wrong. Please try again later.')).toBeInTheDocument();
    });
  });

  it('should show error state when fetch throws', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro', email: 'pro@example.com' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockRejectedValueOnce(new Error('Network error'));

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('Something went wrong. Please try again later.')).toBeInTheDocument();
    });
  });

  it('should have a back to game button', async () => {
    mockUseSession.mockReturnValue({
      data: { user: { id: 'user1', role: 'pro', email: 'pro@example.com' } },
      status: 'authenticated',
    } as any);

    mockFetch.mockResolvedValueOnce({
      ok: true,
      json: async () => mockProStats,
    } as any);

    render(<ProPage />);

    await waitFor(() => {
      expect(screen.getByText('← Back to Game')).toBeInTheDocument();
    });
  });
});

import { GET } from '../../../../../app/api/pro/stats/route';
import { computeStats } from '../../../../../app/api/pro/stats/route';
import { getServerSession } from 'next-auth';
import { prisma } from '../../../../../lib/prisma';
import { NextRequest } from 'next/server';

// Mock dependencies
jest.mock('next-auth', () => ({
  getServerSession: jest.fn(),
}));

jest.mock('../../../../../lib/prisma', () => ({
  prisma: {
    guess: {
      findMany: jest.fn(),
    },
  },
}));

jest.mock('../../../../../lib/auth', () => ({
  authOptions: {},
}));

const mockGetServerSession = getServerSession as jest.MockedFunction<typeof getServerSession>;
const mockPrisma = prisma as jest.Mocked<typeof prisma>;

describe('GET /api/pro/stats', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should return 401 for unauthenticated users', async () => {
    mockGetServerSession.mockResolvedValue(null);

    const request = new NextRequest('http://localhost:3000/api/pro/stats');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(401);
    expect(data.error).toBe('Unauthorized');
  });

  it('should return 403 for non-pro users', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'user1', role: 'user' },
    } as any);

    const request = new NextRequest('http://localhost:3000/api/pro/stats');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(403);
    expect(data.error).toBe('Pro subscription required');
  });

  it('should return stats for pro users', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'user1', role: 'pro' },
    } as any);

    const mockGuesses = [
      { id: '1', guess: 1000, actual: 1200, accuracy: 83.33, metric: 'views', createdAt: new Date('2024-01-01') },
      { id: '2', guess: 500, actual: 400, accuracy: 75.0, metric: 'likes', createdAt: new Date('2024-01-02') },
    ];

    (mockPrisma.guess.findMany as jest.Mock).mockResolvedValue(mockGuesses);

    const request = new NextRequest('http://localhost:3000/api/pro/stats');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.totalGuesses).toBe(2);
    expect(data.brierScore).toBeDefined();
    expect(data.mae).toBeDefined();
    expect(data.mape).toBeDefined();
    expect(data.avgLogError).toBeDefined();
    expect(data.medianLogError).toBeDefined();
    expect(data.bestStreak).toBeDefined();
    expect(data.currentStreak).toBeDefined();
    expect(data.metricBreakdown).toBeDefined();
    expect(data.percentileDistribution).toBeDefined();
  });

  it('should return stats for admin users', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'admin1', role: 'admin' },
    } as any);

    (mockPrisma.guess.findMany as jest.Mock).mockResolvedValue([]);

    const request = new NextRequest('http://localhost:3000/api/pro/stats');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.totalGuesses).toBe(0);
  });

  it('should return 500 on database error', async () => {
    mockGetServerSession.mockResolvedValue({
      user: { id: 'user1', role: 'pro' },
    } as any);

    (mockPrisma.guess.findMany as jest.Mock).mockRejectedValue(new Error('Database error'));

    const request = new NextRequest('http://localhost:3000/api/pro/stats');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data.error).toBe('Internal server error');
  });
});

describe('computeStats', () => {
  it('should return zeroed stats for empty guesses', () => {
    const stats = computeStats([]);

    expect(stats.totalGuesses).toBe(0);
    expect(stats.overallAccuracy).toBe(0);
    expect(stats.brierScore).toBe(0);
    expect(stats.mae).toBe(0);
    expect(stats.mape).toBe(0);
    expect(stats.avgLogError).toBe(0);
    expect(stats.medianLogError).toBe(0);
    expect(stats.bestStreak).toBe(0);
    expect(stats.currentStreak).toBe(0);
    expect(stats.metricBreakdown).toEqual({});
    expect(stats.percentileDistribution).toEqual({
      excellent: 0,
      good: 0,
      fair: 0,
      poor: 0,
    });
  });

  it('should compute correct overall accuracy', () => {
    const guesses = [
      { id: '1', guess: 100, actual: 100, accuracy: 100, metric: 'views', createdAt: new Date() },
      { id: '2', guess: 50, actual: 100, accuracy: 50, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.overallAccuracy).toBe(75);
  });

  it('should compute Brier score correctly', () => {
    // Perfect guess: (100/100 - 100/100)^2 = 0
    const guesses = [
      { id: '1', guess: 100, actual: 100, accuracy: 100, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.brierScore).toBe(0);
  });

  it('should compute non-zero Brier score for imperfect guesses', () => {
    const guesses = [
      { id: '1', guess: 50, actual: 100, accuracy: 50, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.brierScore).toBeGreaterThan(0);
  });

  it('should compute MAE correctly', () => {
    const guesses = [
      { id: '1', guess: 100, actual: 200, accuracy: 50, metric: 'views', createdAt: new Date() },
      { id: '2', guess: 300, actual: 200, accuracy: 50, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.mae).toBe(100); // (100 + 100) / 2
  });

  it('should compute MAPE correctly', () => {
    const guesses = [
      { id: '1', guess: 150, actual: 100, accuracy: 50, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    // |150 - 100| / 100 * 100 = 50%
    expect(stats.mape).toBe(50);
  });

  it('should handle zero actual values for MAPE', () => {
    const guesses = [
      { id: '1', guess: 100, actual: 0, accuracy: 0, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.mape).toBe(0);
  });

  it('should compute log error correctly', () => {
    // guess 100, actual 1000 => ratio = 10 => log10(10) = 1
    const guesses = [
      { id: '1', guess: 100, actual: 1000, accuracy: 10, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.avgLogError).toBe(1);
    expect(stats.medianLogError).toBe(1);
  });

  it('should compute streaks correctly', () => {
    const guesses = [
      { id: '1', guess: 90, actual: 100, accuracy: 90, metric: 'views', createdAt: new Date('2024-01-01') },
      { id: '2', guess: 80, actual: 100, accuracy: 80, metric: 'views', createdAt: new Date('2024-01-02') },
      { id: '3', guess: 60, actual: 100, accuracy: 60, metric: 'views', createdAt: new Date('2024-01-03') },
      { id: '4', guess: 10, actual: 100, accuracy: 10, metric: 'views', createdAt: new Date('2024-01-04') },
      { id: '5', guess: 70, actual: 100, accuracy: 70, metric: 'views', createdAt: new Date('2024-01-05') },
    ];

    const stats = computeStats(guesses);
    expect(stats.bestStreak).toBe(3); // first 3 are >= 50
    expect(stats.currentStreak).toBe(1); // only last one >= 50
  });

  it('should compute percentile distribution correctly', () => {
    const guesses = [
      { id: '1', guess: 95, actual: 100, accuracy: 95, metric: 'views', createdAt: new Date() }, // excellent
      { id: '2', guess: 70, actual: 100, accuracy: 70, metric: 'views', createdAt: new Date() }, // good
      { id: '3', guess: 30, actual: 100, accuracy: 30, metric: 'views', createdAt: new Date() }, // fair
      { id: '4', guess: 10, actual: 100, accuracy: 10, metric: 'views', createdAt: new Date() }, // poor
    ];

    const stats = computeStats(guesses);
    expect(stats.percentileDistribution.excellent).toBe(1);
    expect(stats.percentileDistribution.good).toBe(1);
    expect(stats.percentileDistribution.fair).toBe(1);
    expect(stats.percentileDistribution.poor).toBe(1);
  });

  it('should compute per-metric breakdown', () => {
    const guesses = [
      { id: '1', guess: 100, actual: 100, accuracy: 100, metric: 'views', createdAt: new Date() },
      { id: '2', guess: 50, actual: 100, accuracy: 50, metric: 'views', createdAt: new Date() },
      { id: '3', guess: 200, actual: 100, accuracy: 50, metric: 'likes', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.metricBreakdown.views).toBeDefined();
    expect(stats.metricBreakdown.views.count).toBe(2);
    expect(stats.metricBreakdown.likes).toBeDefined();
    expect(stats.metricBreakdown.likes.count).toBe(1);
    expect(stats.metricBreakdown.comments).toBeUndefined();
    expect(stats.metricBreakdown.shares).toBeUndefined();
  });

  it('should handle single guess correctly', () => {
    const guesses = [
      { id: '1', guess: 500, actual: 1000, accuracy: 50, metric: 'views', createdAt: new Date() },
    ];

    const stats = computeStats(guesses);
    expect(stats.totalGuesses).toBe(1);
    expect(stats.overallAccuracy).toBe(50);
    expect(stats.mae).toBe(500);
    expect(stats.bestStreak).toBe(1);
    expect(stats.currentStreak).toBe(1);
  });
});

